class Solution {
public:
    int racecar(int target) {
        int memo[10005] = {0};
        function<int(int)> dfs = [&](int pos) {
            if (pos == 0) return 0;
            if (memo[pos] > 0) return memo[pos];
            int res = 1e9;
            for (int speed = 1; pos + speed * (1 << (int)log2(speed)) <= target; speed <<= 1) {
                res = min(res, 1 + dfs(-speed));
            }
            memo[pos] = res;
            return res;
        };
        return dfs(target);
    }
};
